@startuml
left to right direction
package "shape" {
  interface Shape {
    + void draw()
  }
  class Circle {
    - void draw()
  }
  class Rectangle {
    - void draw()
  }
  class Square {
    - void draw()
  }
  Circle ..|> Shape : implement
  Rectangle ..|> Shape : implement
  Square ..|> Shape : implement
}

package "color" {
  interface Color {
    + void fill()
  }
  class Blue {
    - void fill()
  }
  class Green {
    - void fill()
  }
  class Red {
    - void fill()
  }
  Blue ..|> Color : implement
  Green ..|> Color : implement
  Red ..|> Color : implement
}

class AbstractFactoryPatternDemo {
  + void main()
}

class FactoryProducer {
  + AbstractFactory getFactory()
}

abstract class AbstractFactory {
  + Shape getShape()
  + Color getColor()
}

class ShapeFactory {
  + Shape getShape()
}

class ColorFactory {
  + Color getColor()
}

AbstractFactoryPatternDemo --> FactoryProducer : ask
FactoryProducer --> AbstractFactory : make
ShapeFactory ..|> AbstractFactory : extends
ColorFactory ..|> AbstractFactory : extends
ShapeFactory --> shape : create
ColorFactory --> color : create
@enduml
